import{_ as e,o as t,c as s,j as r,a as n,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const m=JSON.parse('{"title":"面壁女","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/6.套装/面壁女.md","filePath":"4.资源分区/7.物品与装备/6.套装/面壁女.md"}'),d={name:"4.资源分区/7.物品与装备/6.套装/面壁女.md"};function l(_,a,i,p,b,c){return t(),s("div",null,[...a[0]||(a[0]=[r("h1",{id:"面壁女",tabindex:"-1"},[n("面壁女 "),r("a",{class:"header-anchor",href:"#面壁女","aria-label":'Permalink to "面壁女"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：灵魂蓝调016")])])],-1),o('<h1 id="面壁女-1" tabindex="-1">面壁女 <a class="header-anchor" href="#面壁女-1" aria-label="Permalink to &quot;面壁女&quot;">​</a></h1><p>EGO装备：面壁女<br> 介绍：面壁女（F-01-18）是一个面朝墙壁的人形异想体。它全身赤裸，长有一头长长的，完全遮住面部的黑发。平时，它一直跪在收容单元的地板上，双手压墙，不停地发出抽泣声。在某些情况下，它能把脖子伸成一个极其诡异的长度。<br> 本资源是来自于《脑叶公司》世界，以该异想体的特性制成的两件装备。</p><p>武器：刺耳嚎叫<br> 价格：C+2000<br> 描述：这是一把被充斥着复仇的妖妇所诅咒的十字弩。她的执念使她的长发沿着弩身生长。弩箭弹射所发出的声音会使人联想起她那刺耳的尖叫。持有者在使用这把武器时必须小心，因为弩身上生长着的发丝会紧紧缠住他们的双手，并将他们带入无尽的哀伤之中。唯有坚强的意志与冷酷的内心才能抵御这种哀伤。<br> 这是一张具有9L武器伤害，具有7点高速，具有【双手】特性。<br> 【透穿】：这张弩射出的箭矢带有深重的执念，只为了达成索命的目的，只要在射击之时专心于射杀的想法，那股伤害，怨毒的欲望，就可以引发箭矢所指向方向的生灵的哀嚎。<br> 以一个标准动作，你以这个武器进行一次攻击，这次攻击具有【贯穿】和【接触攻击】以及【法破】特性。<br> 【怨缠】：使用这张弩攻击时，弩上生长的发丝会不断捆缚你的双手，箭矢破空的声音会宛若哀嚎萦绕在你的耳旁，因而使用这把武器，需要有坚强的意志。<br> 如果你不具有决心上的附加成功，则你每以【透穿】攻击一次，你都需要投掷一次机运骰，如果结果为单数，那么你就会流失1点意志力。<br> 每次以【透穿】进行攻击时，你可以令自己承受1点不可避免的心灵来源的耳鸣点数，令这次攻击附带心灵来源的耳鸣点数。</p><p>护甲：刺耳嚎叫<br> 价格：C+1500<br> 描述：妖妇的执念与这件护甲紧紧结合在一起。穿戴者会受困于那令人绝望的复仇魔咒。唯有坚强的意志与冷酷的内心才能抵御这种影响。<br> 这是一套具有10/10点盔甲防御的轻甲。<br> 【精神耐性】：你在穿着这件轻甲时，在意志检定上获得额外的4点器械加值和1点附加成功。<br> 【复仇诅咒】：你在穿着这件轻甲时，在战斗场景中，每轮都会获得4点攻击上的士气加值，并且可以累加，但最多累加3次。当你到达累加的上限之后，如果你不具有决心上的附加成功，每回合则会不可避免地累计1点精神束缚点数。</p><hr><p>Copyright ? 2024 TMDtrpg制作组. All Rights Reserved.</p>',6)])])}const f=e(d,[["render",l]]);export{m as __pageData,f as default};
